mapper.select:
WITH unique_study_ids AS ( SELECT DISTINCT cancer_study_identifier FROM sample_derived
) SELECT gp.stable_id AS stableId, gp.datatype AS datatype, cancer_study.cancer_study_identifier AS cancerStudyIdentifier FROM genetic_profile gp INNER JOIN cancer_study ON gp.cancer_study_id = cancer_study.cancer_study_id
gp.genetic_alteration_type = #{alterationType}
AND gp.datatype != 'CONTINUOUS' AND cancer_study.cancer_study_identifier IN (unique_study_ids);

SELECT gam.entity_stable_id AS stableId, gam.entity_type AS entityType, gam.properties FROM generic_assay_meta_derived gam WHERE gam.entity_stable_id IN ( SELECT DISTINCT entity_stable_id FROM generic_assay_profile_entity_derived WHERE profile_stable_id IN #{item} )
AND gam.entity_stable_id IN #{item}
ORDER BY toUInt32OrZero(extract(gam.entity_stable_id, '^[0-9]+')) ASC, gam.entity_stable_id ASC
